function ValueCell(initialValue) {
  var currentValue = initialValue;
  var watchers = [];
  return {
    val: function () { return currentValue; },
    update: function (f) {
      var oldValue = currentValue;
      currentValue = f(currentValue);
      if (oldValue !== currentValue) watchers.forEach(function (w) { w(currentValue); });
    },
    addWatcher: function (f) { watchers.push(f); },
  };
}

var log = [];
var cell = ValueCell(1);
cell.addWatcher(function (v) { log.push('watcher saw ' + v); });
cell.update(function (v) { return v + 1; });
cell.update(function (v) { return v + 1; });
console.log(cell.val());
console.log(log.join(', '));

