function ValueCell(initialValue) {
  var currentValue = initialValue;
  var watchers = [];
  return {
    val: function () { return currentValue; },
    update: function (f) {
      var oldValue = currentValue;
      currentValue = f(currentValue);
      if (oldValue !== currentValue) watchers.forEach(function (w) { w(currentValue); });
    },
    addWatcher: function (f) { watchers.push(f); },
  };
}
function FormulaCell(upstreamCell, f) {
  var formulaCell = ValueCell(f(upstreamCell.val()));
  upstreamCell.addWatcher(function (newUpstreamValue) {
    formulaCell.update(function () { return f(newUpstreamValue); });
  });
  return formulaCell;
}

var price = ValueCell(10);
var doublePrice = FormulaCell(price, function (p) { return p * 2; });
console.log(doublePrice.val());
price.update(function (p) { return p + 5; });
console.log(doublePrice.val());

